{
  "名称": "纳萨力克地下大坟墓",
  "类型": "游戏公会据点/异世界组织势力",
  "地理位置": "异世界大陆中心区域，北邻都武大森林，西临耶·兰提尔，南临卡兹平原:cite[3]:cite[5]",
  "统治者": "安兹·乌尔·恭（飞鼠）:cite[1]:cite[5]",
  "前身": "YGGDRASIL游戏中“安兹·乌尔·恭”公会的据点，原为六层魔窟，后被改造成十层综合型要塞:cite[3]:cite[5]",
  "历史战绩": "曾抵御八个公会联军及其他相关公会、佣兵NPC合计1500人的讨伐，入侵者全军覆没:cite[3]:cite[5]:cite[8]",
  "阶层结构": [
    {
      "阶层": "第一至第三阶层",
      "环境": "坟墓",
      "守护者": "夏提雅·布拉德弗伦",
      "特点": "有大量的机关、陷阱、法阵、各种不死者，作为最初防御:cite[1]:cite[4]"
    },
    {
      "阶层": "第四阶层",
      "环境": "地底湖",
      "守护者": "高康大",
      "特点": "战略级攻城用哥雷姆，身高超过三十米，需要操作:cite[1]:cite[2]"
    },
    {
      "阶层": "第五阶层",
      "环境": "冰川世界",
      "守护者": "科塞特斯",
      "特点": "覆盖冰川，可对入侵者产生持续冰冻伤害，大坟墓的监狱设于该阶层:cite[1]:cite[4]"
    },
    {
      "阶层": "第六阶层",
      "环境": "森林",
      "守护者": "亚乌菈·贝拉·菲欧拉、马雷·贝罗·菲欧雷",
      "特点": "逼真的人造天空，大量的森林及魔物，森林之外有巨大的圆形竞技场:cite[1]:cite[4]"
    },
    {
      "阶层": "第七阶层",
      "环境": "熔岩世界",
      "守护者": "迪米乌哥斯",
      "特点": "覆盖熔岩，可对入侵者产生持续火焰伤害:cite[1]:cite[4]"
    },
    {
      "阶层": "第八阶层",
      "环境": "荒野",
      "守护者": "威克提姆",
      "特点": "纳萨力克终极防线的一环，拥有死后发动特殊能力:cite[1]:cite[2]"
    },
    {
      "阶层": "第九阶层",
      "环境": "皇家套房",
      "管理者": "塞巴斯·蒂安",
      "特点": "非战斗区域，设施配置等同五星级酒店，无上至尊及仆人侍者居住于此:cite[1]:cite[4]"
    },
    {
      "阶层": "第十阶层",
      "环境": "王座之间",
      "管理者": "雅儿贝德",
      "特点": "核心场所，主要有王座之间，成员集合一般都在王座之间:cite[1]:cite[4]"
    }
  ]
}

