        if (jobs_object && typeof jobs_object === 'object') {
            const updated_jobs = _.cloneDeep(jobs_object);
            let jobsChanged = false;
            for (const key in updated_jobs) {
                if (updated_jobs.hasOwnProperty(key)) {
                    const job = updated_jobs[key];
                    let sumjob_level = 0;
                    // 职业最高等级为10
                    while (job.等级 < 10 && shouldUpgrade(job.当前经验值, job.升级所需经验值)) {
                        jobsChanged = true;
                        job.当前经验值 -= job.升级所需经验值;
                        job.等级 += 1;
                        sumjob_level += 1;
                    }
                    if (sumjob_level > 0) {
                        description += `${key} 升了 ${sumjob_level} 级。`;
                    }

                    if (job.等级 >= 10) {
                        job.等级 = 10;
                    } else {
                        job.升级所需经验值 = Exp_list1[job.等级];
                    }
                }
            }
            if (jobsChanged) {
                anyChanges = true;
                panelUpdates.职业表 = updated_jobs;
            }
        }

        // --- 处理种族表 ---
        let races_object = _.get(current_data, '角色面板.种族表');
        if (typeof races_object === 'string') {
            try {
                races_object = JSON.parse(races_object);
            } catch (e) {
                console.error('解析种族表时出错:', e);
                races_object = null;
            }
        }

        if (races_object && typeof races_object === 'object') {
            const updated_races = _.cloneDeep(races_object);
            let racesChanged = false;
            for (const key in updated_races) {
                if (updated_races.hasOwnProperty(key)) {
                    const race = updated_races[key];
                    let sumrace_level = 0;
                    // 种族最高等级为10
                    while (race.等级 < 10 && shouldUpgrade(race.当前进度, race.升级所需进度)) {
                        racesChanged = true;
                        race.当前进度 -= race.升级所需进度;
                        race.等级 += 1;
                        sumrace_level += 1;
                    }
                    if (sumrace_level > 0) {
                        description += `${key} 升了 ${sumrace_level} 级。`;
                    }

                    race.升级所需进度 = 100; // 升级所需进度固定为100
                    if (race.等级 >= 10) {
                        race.等级 = 10; // 到达满级
                    }
                }
            }
            if (racesChanged) {
                anyChanges = true;
                panelUpdates.种族表 = updated_races;
            }
        }

        // --- 计算总等级并提交更新 ---
        if (anyChanges) {
            let sum_level = 0;
            const final_jobs = panelUpdates.职业表 || jobs_object;
            const final_races = panelUpdates.种族表 || races_object;

            if (final_jobs) {
                for (const key in final_jobs) {
                    sum_level += final_jobs[key].等级 || 0;
                }
            }
            if (final_races) {
                for (const key in final_races) {
                    sum_level += final_races[key].等级 || 0;
                }
            }

            panelUpdates.总等级 = sum_level;
            panelUpdates.升级标志 = description.trim();

            const updatePayload = { 角色面板: panelUpdates };

            eventEmit('era:updateByObject', updatePayload);
            console.log('已触发升级更新事件:', updatePayload);
            toastr.info(`升级了！${description}`);
        }

    } catch (e) {
        console.error('经验值管理错误:', e);
    }
});

