function get_alignment_text(alignment) {
    // 确保善恶值在-1000到1000的范围内
    alignment = Math.max(-1000, Math.min(1000, alignment));

    if (alignment <= -801) {
        return alignment_list[0];
    } else if (alignment <= -601) {
        return alignment_list[1];
    } else if (alignment <= -401) {
        return alignment_list[2];
    } else if (alignment <= -201) {
        return alignment_list[3];
    } else if (alignment <= 200) {
        return alignment_list[4];
    } else if (alignment <= 400) {
        return alignment_list[5];
    } else if (alignment <= 600) {
        return alignment_list[6];
    } else if (alignment <= 800) {
        return alignment_list[7];
    } else {
        return alignment_list[8];
    }
}

// 新增：用于管理单个实体（如角色、NPC）的阵营属性
function manageAlignment(current_entity, last_entity) {
    const updates = {};
    let changed = false;

    if (!current_entity || !last_entity) {
        return { changed: false, updates: {} };
    }

    const current_alignment_value = _.get(current_entity, '阵营属性.善恶值');
    if (typeof current_alignment_value === 'undefined') {
        return { changed: false, updates: {} };
    }

    const original_alignment_description = _.get(current_entity, '阵营属性.阵营描述');
    let new_alignment_value = current_alignment_value;
    const last_alignment_value = _.get(last_entity, '阵营属性.善恶值', current_alignment_value);

    let difference = new_alignment_value - last_alignment_value;

    if (difference > 10) {
        new_alignment_value = last_alignment_value + 10;
    } else if (difference < -10) {
        new_alignment_value = last_alignment_value - 10;
    }

    new_alignment_value = Math.max(-1000, Math.min(1000, new_alignment_value));
    const new_alignment_description = get_alignment_text(new_alignment_value);

    if (new_alignment_value !== current_alignment_value || new_alignment_description !== original_alignment_description) {
        updates.善恶值 = new_alignment_value;
        updates.阵营描述 = new_alignment_description;
        changed = true;
    }

    return { changed, updates };
}

// 新增：用于处理包含多个实体的列表（如关系列表、敌人列表）
function processEntityList(current_list, last_list) {
    const listUpdates = {};
    let anyListChanges = false;

    if (typeof current_list === 'string') {
        try {
            current_list = JSON.parse(current_list);
        } catch (e) {
            return { anyListChanges: false, listUpdates: {} };
        }
    }

    if (typeof last_list === 'string') {
        try {
            last_list = JSON.parse(last_list);
        } catch (e) {
            last_list = {};
        }
    }
    last_list = last_list || {};

    if (!current_list || typeof current_list !== 'object') {
        return { anyListChanges: false, listUpdates: {} };
    }

    for (const key in current_list) {
        if (current_list.hasOwnProperty(key)) {
            const current_entity = current_list[key];
            const last_entity = _.get(last_list, key, {});

            const result = manageAlignment(current_entity, last_entity);

            if (result.changed) {
                _.set(listUpdates, `${key}.阵营属性`, result.updates);
                anyListChanges = true;
            }
        }
    }

    return { anyListChanges, listUpdates };
}

eventOn('era:writeDone', (detail) => {
    const current_data = detail.stat;
    if (!current_data) {
        return;
    }

    try {
        let last_data_str = window.localStorage.getItem('阵营系统_last_data');
        let last_data = last_data_str ? JSON.parse(last_data_str) : {};

        const allUpdates = {};
        let anyChanges = false;

        // --- 处理角色面板 ---
        const playerPanelResult = manageAlignment(_.get(current_data, '角色面板'), _.get(last_data, '角色面板'));
        if (playerPanelResult.changed) {
            _.set(allUpdates, '角色面板.阵营属性', playerPanelResult.updates);
            anyChanges = true;
        }

        // --- 处理关系列表 ---
        const relationsResult = processEntityList(_.get(current_data, '关系列表'), _.get(last_data, '关系列表'));
        if (relationsResult.anyListChanges) {
            allUpdates.关系列表 = relationsResult.listUpdates;
            anyChanges = true;
        }

        // --- 处理敌人列表 ---
        const enemiesResult = processEntityList(_.get(current_data, '敌人列表'), _.get(last_data, '敌人列表'));
        if (enemiesResult.anyListChanges) {
            allUpdates.敌人列表 = enemiesResult.listUpdates;
            anyChanges = true;
        }

        // --- 提交更新 ---
        if (anyChanges) {
            eventEmit('era:updateByObject', allUpdates);
        }

    } catch (e) {
        console.error('阵营系统处理出错:', e);
    } finally {
        window.localStorage.setItem('阵营系统_last_data', JSON.stringify(current_data));
    }
});

