eventOn('era:writeDone', (detail) => {
    const current_data = detail.stat;
    if (!current_data) {
        return;
    }

    try {
        let last_data_str = window.localStorage.getItem('好感度_last_data');
        let last_data = last_data_str ? JSON.parse(last_data_str) : {};

        const current_object_list = _.get(current_data, '关系列表') || {};
        const last_object_list = _.get(last_data, '关系列表') || {};

        let updates = {};
        let has_updates = false;

        for (let key in current_object_list) {
            if (current_object_list.hasOwnProperty(key)) {
                const child_object = current_object_list[key];

                if (typeof child_object.好感度 === 'undefined') {
                    continue;
                }

                let current_likeability = child_object.好感度;
                const original_likeability = current_likeability;
                const original_attitude = child_object.对你态度;

                if (last_object_list.hasOwnProperty(key) && typeof last_object_list[key].好感度 !== 'undefined') {
                    const last_likeability = last_object_list[key].好感度;
                    let difference = current_likeability - last_likeability;

                    if (difference > 5) {
                        current_likeability = last_likeability + 5;
                    } else if (difference < -5) {
                        current_likeability = last_likeability - 5;
                    }
                }

                current_likeability = Math.max(-100, Math.min(100, current_likeability));

                let new_attitude_text = original_attitude;
                const sex = child_object.性别;
                if (sex === '男') {
                    new_attitude_text = get_man_likeability_text(current_likeability);
                } else if (sex === '女') {
                    new_attitude_text = get_woman_likeability_text(current_likeability);
                }

                if (current_likeability !== original_likeability || new_attitude_text !== original_attitude) {
                    updates[key] = {
                        好感度: current_likeability,
                        对你态度: new_attitude_text,
                    };
                    has_updates = true;
                }
            }
        }

        if (has_updates) {
            eventEmit('era:updateByObject', { '关系列表': updates });
        }

    } catch (e) {
        console.error('好感度系统处理出错:', e);
    } finally {
        window.localStorage.setItem('好感度_last_data', JSON.stringify(current_data));
    }
});

