let Exp_list1 = [0, 1000, 3000, 6000, 10000, 15000, 21000, 28000, 36000, 45000]; // 职业升级经验需求



function shouldUpgrade(currentExp, neededExp) {
    if(currentExp >= neededExp) {
        return true;
    }
    return false;
}
function manageExperience(variables) {
    const original_sum_level = _.get(variables, 'stat_data.角色面板.总等级');
    let new_sum_level = 0;
    let description = "";
    let list1Changed = false;
    let list2Changed = false;

    // 职业表
    const list1Data = _.get(variables, 'stat_data.角色面板.职业表');
    if (list1Data) {
        try {
            const list1_object = typeof list1Data === 'string' ? JSON.parse(list1Data) : list1Data;
            for (const key in list1_object) {
                if (list1_object.hasOwnProperty(key)) {
                    const job = list1_object[key];
                    let sumjob_level = 0;
                    while (job.等级 < Exp_list1.length && shouldUpgrade(job.当前经验值, job.升级所需经验值)) {
                        list1Changed = true;
                        job.当前经验值 -= job.升级所需经验值;
                        job.等级 += 1;
                        sumjob_level += 1;
                        job.升级所需经验值 = Exp_list1[job.等级];
                    }
                    if (sumjob_level > 0) {
                        description += `${key} 已经升级了${sumjob_level}级 `;
                    }
                    if (job.等级 < Exp_list1.length) {
                        job.升级所需经验值 = Exp_list1[job.等级];
                    } else {
                        job.等级 = 10; // 达到最高等级
                    }
                    new_sum_level += job.等级;
                }
            }
            if (list1Changed) {
                _.set(variables, 'stat_data.角色面板.职业表', JSON.stringify(list1_object));
            }
        } catch (e) {
            console.error('解析职业表时出错:', e);
        }
    }

    // 种族表
    const list2Data = _.get(variables, 'stat_data.角色面板.种族表');
    if (list2Data) {
        try {
            const list2_object = typeof list2Data === 'string' ? JSON.parse(list2Data) : list2Data;
            for (const key in list2_object) {
                if (list2_object.hasOwnProperty(key)) {
                    const race = list2_object[key];
                    let sumrace_level = 0;
                    while (shouldUpgrade(race.当前进度, race.升级所需进度)) {
                        list2Changed = true;
                        race.当前进度 -= race.升级所需进度;
                        race.等级 += 1;
                        sumrace_level += 1;
                    }
                    if (sumrace_level > 0) {
                        description += `${key} 已经升级了${sumrace_level}级 `;
                    }
                    // 确保所需进度始终是正确的
                    race.升级所需进度 = 100;
                    if (race.等级 > 10) {
                        race.等级 = 10; // 达到最高等级
                    }
                    new_sum_level += race.等级; 
                }
            }
            if (list2Changed) {
                _.set(variables, 'stat_data.角色面板.种族表', JSON.stringify(list2_object));
            }
        } catch (e) {
            console.error('解析种族表时出错:', e);
        }
    }


    const totalLevelChanged = original_sum_level !== new_sum_level;
    if (totalLevelChanged) {
        _.set(variables, 'stat_data.角色面板.总等级', new_sum_level);
    }


    if (description) {
        _.set(variables, 'stat_data.角色面板.升级标志', description);
    }


    const anyChanges = list1Changed || list2Changed || totalLevelChanged;
    return { changed: anyChanges };
}
