    };

    const getPortrait = (name) => {
        if (!name) return null;
        for (const key in characterPortraits) {
            const parts = key.split(/[·・]/); // Split by '·' or '・'
            if (parts.some(part => name.includes(part))) {
                return characterPortraits[key];
            }
        }
        return null;
    };

    const getPercentage = (stat) => {
        if (!stat || stat.最大值 == null || stat.最大值 === 0 || stat.当前值 == null) return 0;
        return Math.min(100, Math.max(0, (stat.当前值 / stat.最大值) * 100));
    };

    const objectToArray = (obj) => {
        if (!obj || typeof obj !== 'object') return [];
        return Object.entries(obj)
            .filter(([key]) => !key.startsWith('$'))
            .map(([, value]) => value)
            .filter(value => value && typeof value === 'object' && (value.姓名 || value.物品名称 || value.职业 || value.种族 || value.name));
    };

    const filteredEntries = (obj) => {
        if (!obj || typeof obj !== 'object') return [];
        return Object.entries(obj).filter(([key]) => !key.startsWith('$'));
    };

    const relationCard = {
        props: { npc: { type: Object, required: true } },
        setup(props) {
            const isDetailsVisible = ref(false);
            const toggleDetails = () => { isDetailsVisible.value = !isDetailsVisible.value; };
            const portrait = computed(() => getPortrait(props.npc.姓名));
            return { isDetailsVisible, toggleDetails, getPercentage, objectToArray, filteredEntries, portrait };
