                            <div class="progress-bar"><div class="progress-bar-fill hp" :style="{ width: getPercentage(npc.能力表.HP) + '%' }"></div></div>
                        </div>
                        <div class="stat-item" style="margin-top: 0.5rem;">
                            <span class="stat-label">MP: {{ npc.能力表.MP?.当前值 ?? 'N/A' }} / {{ npc.能力表.MP?.最大值 ?? 'N/A' }}</span>
