                                <div>
                                    <div class="item-name">[{{ slot }}] {{ equip.name || '无' }}</div>
                                    <div class="item-desc" v-if="equip.name">{{ equip.description }}</div>
                                </div>
                            </li>
                        </ul>
                    </div>
                </section>
            </div>
        `
    };

    const enemyCard = {
        props: { npc: { type: Object, required: true } },
        setup(props) {
            const isDetailsVisible = ref(false);
            const toggleDetails = () => { isDetailsVisible.value = !isDetailsVisible.value; };
            const portrait = computed(() => getPortrait(props.npc.姓名));
            return { isDetailsVisible, toggleDetails, getPercentage, objectToArray, filteredEntries, portrait };
        },
        template: `
            <div class="card enemy-card">
                <header class="card-header" @click="toggleDetails">
                    <div style="flex: 1;">
                        <div class="card-name">{{ npc.姓名 || '无名者' }}</div>
                        <div class="card-desc">{{ npc.种族 || '未知种族' }} · 总等级 {{ npc.总等级 ?? '未知' }}</div>
                    </div>
                    <img v-if="portrait" :src="portrait" class="card-portrait">
                    <span class="toggle-icon" :class="{ collapsed: !isDetailsVisible }">▼</span>
