        computed: {
            characterPanel() {
                if (!this.mvuData) return null;
                try { return Mvu.getMvuVariable(this.mvuData, '角色面板', { category: 'stat' }); }
                catch (e) { console.error('获取角色面板数据时发生错误:', e); this.error = '无法读取角色面板数据'; return null; }
            },
            factionPanel() {
                if (!this.mvuData) return null;
                try {
                    const panel = Mvu.getMvuVariable(this.mvuData, '势力面板', { category: 'stat' });
                    return panel;
                }
                catch (e) {
                    console.log('势力面板不存在或获取失败:', e);
                    return null;
                }
            },
            relationsList() {
                if (!this.mvuData) return [];
                try {
                    const data = Mvu.getMvuVariable(this.mvuData, '关系列表', { category: 'stat' });
                    return this.objectToArray(data || {});
                } catch (e) {
                    console.error('获取关系列表数据时发生错误:', e);
                    return [];
                }
            },
            enemiesList() {
                if (!this.mvuData) return [];
                try {
                    const data = Mvu.getMvuVariable(this.mvuData, '敌人列表', { category: 'stat' });
                    return this.objectToArray(data || {});
                } catch (e) {
                    console.error('获取敌人列表数据时发生错误:', e);
                    return [];
                }
            },
            currentSongName() {
                if (!this.musicList.length) return '无音乐';
                const url = this.musicList[this.currentTrackIndex];
                try {
                    const decodedUrl = decodeURIComponent(url);
                    const filename = decodedUrl.substring(decodedUrl.lastIndexOf('/') + 1);
                    return filename.replace('.mp3', '').replace(/_/g, ' ');
                } catch (e) {
                    return '未知曲目';
                }
            },
        },
        methods: {
            getPercentage,
            togglePanel(panel) { this.toggledPanels[panel] = !this.toggledPanels[panel]; },
            isPanelVisible(panel) { return !!this.toggledPanels[panel]; },
            async updateMvuData() {
                if (this.isUpdating) return;
                this.isUpdating = true;
                this.error = null;
                try {
                    this.mvuData = await Mvu.getMvuData({ type: 'chat' });
                } catch(e) {
                    this.error = "加载游戏数据失败。请检查MVU扩展是否正常工作。";
                    console.error("MVU Data fetch failed:", e);
                } finally {
                    this.isUpdating = false;
                }
            },
            objectToArray,
            filteredEntries,
            // Initializes and plays audio.
            setupMusicPlayerAndPlay() {
                if (this.musicList.length === 0) return;

                this.audio = new Audio();
                this.audio.src = this.musicList[this.currentTrackIndex];
                this.audio.loop = false;
                this.audio.addEventListener('ended', this.nextTrack);

                this.audio.play().then(() => {
                    this.isPlaying = true;
                }).catch(e => {
                    console.error("音频播放失败:", e);
                    this.isPlaying = false;
                });
            },
            togglePlay() {
                if (!this.audio) {
                    this.setupMusicPlayerAndPlay();
                    return;
                }

                if (this.isPlaying) {
                    this.audio.pause();
                    this.isPlaying = false;
                } else {
                    this.audio.play().then(() => {
                        this.isPlaying = true;
                    }).catch(e => {
                        console.error("音频播放失败:", e);
                        this.isPlaying = false;
                    });
                }
            },
            playTrack(index) {
                if (index < 0 || index >= this.musicList.length) return;
                this.currentTrackIndex = index;

                if (!this.audio) {
                    this.setupMusicPlayerAndPlay();
                } else {
                    this.audio.src = this.musicList[this.currentTrackIndex];
                    this.audio.play().then(() => {
                        this.isPlaying = true;
                    }).catch(e => {
                        console.error("音频播放失败:", e);
                        this.isPlaying = false;
                    });
                }
            },
            nextTrack() {
                const newIndex = (this.currentTrackIndex + 1) % this.musicList.length;
                this.playTrack(newIndex);
            },
            prevTrack() {
                const newIndex = (this.currentTrackIndex - 1 + this.musicList.length) % this.musicList.length;
                this.playTrack(newIndex);
            },
        },
        async mounted() {
            if (typeof Mvu === 'undefined') {
                this.error = "环境错误: 缺少必要的SillyTavern函数(Mvu)。请在支持此扩展的环境中运行。";
                console.error(this.error);
                return;
            }
            await this.updateMvuData();
            console.log("OVERLORD status panel initialized.");
        }
    });

    app.mount('#app');
    </script>
</body>
</html>
