        <fieldset>
            <legend>阵营属性</legend>
            <div class="form-group"><label for="alignment-value">善恶值:</label><input type="number" id="alignment-value" value="0" min="-1000" max="1000" oninput="handleMinMaxInput(this)"></div>
        </fieldset>

        <fieldset>
            <legend>背包</legend>
            <div class="table-wrapper">
                <table class="dynamic-table">
                    <thead><tr><th>物品名称</th><th>数量</th><th>描述</th><th>操作</th></tr></thead>
                    <tbody id="inventory-tbody"></tbody>
                </table>
            </div>
            <button type="button" class="add-button" onclick="addRow('inventory-tbody', 'inventory-template')">添加物品</button>
        </fieldset>

        <fieldset>
            <legend>装备栏</legend>
            <div class="equipment-container">
                <div class="equipment-card">
                    <h2>武器</h2>
                    <div class="form-group"><label>名称:</label><input type="text" name="装备_武器_名称"></div>
                    <div class="form-group"><label>AD:</label><input type="number" name="装备_武器_AD"></div>
                    <div class="form-group"><label>AP:</label><input type="number" name="装备_武器_AP"></div>
                    <div class="form-group"><label>描述:</label><textarea name="装备_武器_描述"></textarea></div>
                </div>
                <div class="equipment-card">
                    <h2>头部</h2>
                    <div class="form-group"><label>名称:</label><input type="text" name="装备_头部_名称"></div>
                    <div class="form-group"><label>物理防御:</label><input type="number" name="装备_头部_PhyDef"></div>
                    <div class="form-group"><label>魔法防御:</label><input type="number" name="装备_头部_MagDef"></div>
                    <div class="form-group"><label>描述:</label><textarea name="装备_头部_描述"></textarea></div>
                </div>
                <div class="equipment-card">
                    <h2>上身</h2>
                    <div class="form-group"><label>名称:</label><input type="text" name="装备_上身_名称"></div>
                    <div class="form-group"><label>物理防御:</label><input type="number" name="装备_上身_PhyDef"></div>
                    <div class="form-group"><label>魔法防御:</label><input type="number" name="装备_上身_MagDef"></div>
                    <div class="form-group"><label>描述:</label><textarea name="装备_上身_描述"></textarea></div>
                </div>
                <div class="equipment-card">
                    <h2>下身</h2>
                    <div class="form-group"><label>名称:</label><input type="text" name="装备_下身_名称"></div>
                    <div class="form-group"><label>物理防御:</label><input type="number" name="装备_下身_PhyDef"></div>
                    <div class="form-group"><label>魔法防御:</label><input type="number" name="装备_下身_MagDef"></div>
                    <div class="form-group"><label>描述:</label><textarea name="装备_下身_描述"></textarea></div>
                </div>
                <div class="equipment-card">
                    <h2>饰品A</h2>
                    <div class="form-group"><label>名称:</label><input type="text" name="装备_饰品A_名称"></div>
                    <div class="form-group"><label>描述:</label><textarea name="装备_饰品A_描述"></textarea></div>
                </div>
                <div class="equipment-card">
                    <h2>饰品B</h2>
                    <div class="form-group"><label>名称:</label><input type="text" name="装备_饰品B_名称"></div>
                    <div class="form-group"><label>描述:</label><textarea name="装备_饰品B_描述"></textarea></div>
                </div>
            </div>
        </fieldset>

        <fieldset>
            <legend>法术技能</legend>
            <div class="table-wrapper">
                <table class="dynamic-table">
                    <thead><tr><th>名称</th><th>等级</th><th>消耗MP</th><th>伤害</th><th>描述</th><th>操作</th></tr></thead>
                    <tbody id="spell-tbody"></tbody>
                </table>
            </div>
            <button type="button" class="add-button" onclick="addRow('spell-tbody', 'spell-template')">添加法术</button>
        </fieldset>

        <fieldset>
            <legend>背景描述</legend>
            <div class="form-group">
                <label for="background-preset-select">背景预设:</label>
                <select id="background-preset-select">
                    <option value="">--- 请选择预设或自定义 ---</option>
                    <option value="开场白1">开场白1：剑圣与飞鼠</option>
                    <option value="开场白2">开场白2：图书馆穿越者</option>
                    <option value="自定义">自定义</option>
                </select>
            </div>
            <div class="form-group"><label for="background-story">背景故事:</label><textarea id="background-story" style="min-height: 160px;"></textarea></div>
        </fieldset>
        <button type="button" id="confirm-btn" style="width: 100%; padding: 15px; font-size: 1.5rem; margin-top: 20px; background-color: #8b4513; color: white; border: none; border-radius: 5px; cursor: pointer;">确认并生成</button>
    </form>
</div>

<!-- Templates -->
<template id="class-template"><tr><td><input type="text" name="职业_职业"></td><td><input type="number" name="职业_等级" value="0" min="0" max="10" oninput="handleMinMaxInput(this)"></td><td><input type="text" name="职业_description"></td><td><button type="button" class="delete-button" onclick="deleteRow(this)">删除</button></td></tr></template>
<template id="race-template"><tr><td><input type="text" name="种族_种族"></td><td><input type="number" name="种族_等级" value="0" min="0" max="10" oninput="handleMinMaxInput(this)"></td><td><input type="text" name="种族_description"></td><td><button type="button" class="delete-button" onclick="deleteRow(this)">删除</button></td></tr></template>
<template id="inventory-template"><tr><td><input type="text"></td><td><input type="number"></td><td><input type="text"></td><td><button type="button" class="delete-button" onclick="deleteRow(this)">删除</button></td></tr></template>
<template id="spell-template"><tr><td><input type="text"></td><td><input type="number" min="0" max="11" oninput="handleMinMaxInput(this)"></td><td><input type="number" min="0" oninput="handleMinMaxInput(this)"></td><td><input type="text"></td><td><input type="text"></td><td><button type="button" class="delete-button" onclick="deleteRow(this)">删除</button></td></tr></template>

<script>
    document.addEventListener('DOMContentLoaded', () => {
        // --- Race Data and Population ---
        const raceData = {
          "OVERLOD种族体系": {
            "人类": { "description": "最普通、最常见的种族，异世界土著居民的主体" },
            "亚人类": {
              "description": "拥有人类特征但同时具备其他生物特征的种族",
              "种族类型": { "兽人": "拥有人形但带有野兽特征（如狼人、虎人）", "哥布林": "矮小的绿色亚人，通常群体行动", "食人魔": "巨大而强壮的亚人，力量出众", "蜥蜴人": "拥有鳞片和尾巴的亚人种，擅长水中战斗" }
            },
            "异形类": {
              "description": "YGGDRASIL玩家可选种族的核心部分，力量通常远超人类和亚人类",
              "不死者": { "种族等级": { "低级不死者": ["僵尸", "骷髅"], "中级不死者": ["幽灵", "尸妖"], "高级不死者": ["死者大魔法师", "吸血鬼", "Overlord"] } },
              "恶魔": { "种族等级": { "下级恶魔": ["小恶魔", "劣魔"], "中级恶魔": ["魅魔", "狂战魔"], "上级恶魔": ["巴洛炎魔", "最高阶恶魔"] } },
              "天使": { "种族等级": { "下位天使": ["小天使", "权天使"], "中位天使": ["主天使", "力天使"], "上位天使": ["智天使", "炽天使"] } },
              "精灵": { "分支": ["森林精灵", "黑暗精灵", "高等精灵"] },
              "自动人偶": { "变种": ["粘液仿造人偶", "狼人混自动人偶", "普通哥雷姆"] }
            },
            "神人": { "description": "拥有部分神灵血统或特性的稀有种族" },
            "龙族": { "description": "YGGDRASIL中最顶级的种族之一" }
          }
        };

        function populateRaces() {
            const raceSelect = document.getElementById('race');
            if (!raceSelect) return;

            const raceSystem = raceData.OVERLOD种族体系;

            const createOption = (value, text) => {
                const option = document.createElement('option');
                option.value = value;
                option.textContent = text || value;
                return option;
            };

            const createOptgroup = (label) => {
                const optgroup = document.createElement('optgroup');
                optgroup.label = label;
                return optgroup;
            };

            raceSelect.appendChild(createOption('', '--- 请选择一个种族 ---'));
            raceSelect.appendChild(createOption('人类'));
            raceSelect.appendChild(createOption('精灵'));
            raceSelect.appendChild(createOption('矮人'));
            raceSelect.appendChild(createOption('半精灵'));

            const subhumanGroup = createOptgroup('亚人类');
            for (const race in raceSystem.亚人类.种族类型) {
                subhumanGroup.appendChild(createOption(race));
            }
            raceSelect.appendChild(subhumanGroup);

            const heteromorphicGroup = createOptgroup('异形类');
            const heteroTypes = raceSystem.异形类;

            Object.values(heteroTypes.不死者.种族等级).flat().forEach(race => heteromorphicGroup.appendChild(createOption(race, `不死者 - ${race}`)));
            Object.values(heteroTypes.恶魔.种族等级).flat().forEach(race => heteromorphicGroup.appendChild(createOption(race, `恶魔 - ${race}`)));
            Object.values(heteroTypes.天使.种族等级).flat().forEach(race => heteromorphicGroup.appendChild(createOption(race, `天使 - ${race}`)));
            heteroTypes.精灵.分支.forEach(race => heteromorphicGroup.appendChild(createOption(race, `精灵 - ${race}`)));
            heteroTypes.自动人偶.变种.forEach(race => heteromorphicGroup.appendChild(createOption(race, `自动人偶 - ${race}`)));
            raceSelect.appendChild(heteromorphicGroup);

            raceSelect.appendChild(createOption('神人'));
            raceSelect.appendChild(createOption('龙族'));
            raceSelect.appendChild(createOption('自定义'));
        }

        populateRaces();

        const raceSelect = document.getElementById('race');
        const customRaceGroup = document.getElementById('race-custom-group');
        const customRaceInput = document.getElementById('race-custom');

        raceSelect.addEventListener('change', () => {
            if (raceSelect.value === '自定义') {
                customRaceGroup.classList.remove('hidden');
            } else {
                customRaceGroup.classList.add('hidden');
                customRaceInput.value = ''; // Clear custom input when switching away
            }
        });

        // --- Background Story Presets ---
        const backgroundPresets = {
            "开场白1": `王座间内，最后一名公会成员「泡泡茶壶」化作光粒消散。只余下骷髅魔法师飞鼠与倚靠石柱而立的「剑圣」。\n「你也…没退出吗？」飞鼠的声音带着电子音的空洞。\n剑圣——此刻被名为{{user}}的大学生意识占据——轻抚腰间佩剑【天照云切】。这具身体传来的真实触感让{{user}}心生违和。\n「只是想…多看几眼罢了。」\n倒计时在视野角落闪烁。两人简短回忆起并肩作战的岁月——在「极剑渊」的七十二小时鏖战，对抗「百鬼夜行」的坚守。每一段记忆都让即将到来的永别更加沉重。\n「大家…都走了啊。」飞鼠喃喃道。\n「但这段冒险，是我人生中最棒的时光。」剑圣平静回应，右手无意识握紧剑柄。\n当倒计时归零，撕裂灵魂的剧痛取代了预期的断线。数据洪流中，剑圣本能地抓住公会戒指与剑柄。\n意识恢复时，一切都不同了。\n石材的冰冷，空气中魔法的气息，肌肉中烙印的剑技——一切都真实得可怕。\n剑圣抬眼，看见王座上已非像素骷髅，而是散发死亡威压的不死者之王。那猩红魂火同样映照着震惊。\n「剑圣…？」真实的声音在厅中回荡。\n{{user}}感受着与佩剑的血脉相连，沉声回应：\n「飞鼠…我们，似乎回不去了。」\n月光将两道身影投在冰冷地面上——掌握至高死之魔法的骷 chiffres，与精通巅峰剑技的武者，一同被困在了这个突然变得真实的世界。`,
            "开场白2": `一双森白的骨掌映入视野，正自然地交叠在安兹·乌尔·恭之杖上。尝试着动了动其中一根指骨，那骨头便顺从地弯曲，发出微不可闻的摩擦声。\n\n「这……不是我的身体。我记得我还在图书馆学习啊。」\n\n这个认知带着绝对的寒意贯穿了{{user}}的整个存在。\n\n仿佛是为了印证这一点，一股浩瀚的知识洪流自然而然地在{{user}}意识中浮现——无数{{user}}从未学过的魔法咒文、纳萨力克地下大坟墓的详尽结构、每一位NPC守护者的创造背景与忠诚度、以及属于不死者之王的庞大力量感。这一切都如同与生俱来般熟悉。\n。\n\n{{user}}的发声器官，或者说，{{user}}用来产生声音的魔法构造，自动运作起来，发出了低沉而带着威严共鸣的嗓音，那正是属于不死者之王的声音：\n\n「……啊」\n\n{{user}}缓缓从王座上站起，高大的骷髅身躯在火炬光下拉出长长的阴影。安兹·乌尔·恭之杖的底端与地面接触，发出清脆而冰冷的敲击声，在这死寂的大厅中回荡。\n\n{{user}}迈步走向那面巨大的水晶窗，窗外的景象让{{user}}眼眶中的红光微微波动——那不再是遥远的地球华夏，而是一片真实的、陌生的夜空，两轮大小不一的月亮正散发着妖异而冰冷的光辉。\n\n{{user}}抬起一只骨手，缓缓握紧。\n\n指节发出清脆的摩擦声。\n\n{{user}}的平凡人生在此刻彻底落幕。\n\n从现在起，{{user}}必须，也只能是纳萨力克地下大坟墓的唯一至尊，安兹·乌尔·恭。`
        };

        const backgroundSelect = document.getElementById('background-preset-select');
        const backgroundTextarea = document.getElementById('background-story');

        backgroundSelect.addEventListener('change', () => {
            const selectedValue = backgroundSelect.value;
            if (backgroundPresets[selectedValue]) {
                backgroundTextarea.value = backgroundPresets[selectedValue];
            } else {
                backgroundTextarea.value = ''; // Clear for "自定义" or default
            }
        });

        // --- Page Transition ---
        const coverScreen = document.getElementById('cover-screen');
        const startBtn = document.getElementById('start-btn');
        const characterSheet = document.getElementById('character-sheet');

        startBtn.addEventListener('click', () => {
            coverScreen.style.opacity = '0';
            setTimeout(() => {
                coverScreen.classList.add('hidden');
                document.body.style.overflow = 'auto';
                document.body.style.background = "#fdf5e6 url('https://www.transparenttextures.com/patterns/old-paper.png')";
                characterSheet.classList.remove('hidden');
            }, 1000);
        });

        // --- Initial Rows ---
        addRow('class-tbody', 'class-template');
        addRow('race-tbody', 'race-template');
        addRow('inventory-tbody', 'inventory-template');
        addRow('spell-tbody', 'spell-template');
        updateTotalLevel();

        // --- Event Delegation for Level Calculation ---
        const sheet = document.getElementById('character-sheet');
        sheet.addEventListener('input', (event) => {
            if (event.target.name === '职业_等级' || event.target.name === '种族_等级') {
                updateTotalLevel();
            }
        });

        document.getElementById('confirm-btn').addEventListener('click', async () => {
            // --- Validation ---
            if (typeof toastr === 'undefined') {
                console.error('Toastr not loaded!');
                alert('A required library is missing. Please check the console.');
                return;
            }

            // 1. Basic Info
            const basicInfoFields = [
                { id: 'name', name: '姓名' },
                { id: 'gender', name: '性别' },
                { id: 'race', name: '种族' },
                { id: 'age', name: '年龄' }
            ];

            for (const field of basicInfoFields) {
                const element = document.getElementById(field.id);
                if (!element || element.value.trim() === '') {
                    toastr.warning(`基本信息 "${field.name}" 是必须的。`);
                    return;
                }
            }

            // 1.5. Custom Race Validation
            if (document.getElementById('race').value === '自定义' && document.getElementById('race-custom').value.trim() === '') {
                toastr.warning('请输入自定义种族名称。');
                return;
            }

            // 2. Ability Scores
            const abilityFieldset = Array.from(document.querySelectorAll('legend')).find(lg => lg.textContent === '能力表').parentElement;
            if (abilityFieldset) {
                const abilityInputs = abilityFieldset.querySelectorAll('input[type="number"]');
                for (const input of abilityInputs) {
                    if (input.value.trim() === '') {
                        const label = input.previousElementSibling;
                        toastr.warning(`能力表 "${label.textContent.replace(':', '')}" 是必须的。`);
                        return;
                    }
                }
            }
            // --- End Validation ---
            try {
                if (typeof toastr !== 'undefined') toastr.info('稍等，角色数据更新中...');

                // Helper functions
                const getValue = (id) => (document.getElementById(id)?.value || '').trim();
                const getNumber = (value) => {
                    const strValue = value === null || value === undefined ? '' : String(value).trim();
                    if (strValue === '') {
                        return null;
                    }
                    const num = parseInt(strValue, 10);
                    return isNaN(num) ? null : num;
                };
                const getNumberValue = (id) => getNumber(document.getElementById(id)?.value);

                const getAbilityValue = (label) => {
                    const labels = Array.from(document.querySelectorAll('#character-sheet fieldset:nth-of-type(4) .form-group label'));
                    const targetLabel = labels.find(l => l.textContent === label);
                    if (targetLabel && targetLabel.nextElementSibling) {
                        return getNumber(targetLabel.nextElementSibling.value);
                    }
                    return null;
                };

                const getTableData = (tbodyId) => {
                    const tbody = document.getElementById(tbodyId);
                    if (!tbody) return {};
                    const rows = Array.from(tbody.querySelectorAll('tr'));
                    const data = {};

                    rows.forEach(row => {
                        const inputs = Array.from(row.querySelectorAll('input'));
                        const name = inputs[0].value.trim();
                        if (!name) return;

                        if (tbodyId === 'class-tbody') {
                            data[name] = { "职业": name, "等级": getNumber(inputs[1].value), "description": inputs[2].value.trim() };
                        } else if (tbodyId === 'race-tbody') {
                            data[name] = { "种族": name, "等级": getNumber(inputs[1].value), "description": inputs[2].value.trim() };
                        } else if (tbodyId === 'inventory-tbody') {
                            data[name] = { "物品名称": name, "数量": getNumber(inputs[1].value), "描述": inputs[2].value.trim() };
                        } else if (tbodyId === 'spell-tbody') {
                            data[name] = { "name": name, "level": getNumber(inputs[1].value), "消耗MP": getNumber(inputs[2].value), "伤害": inputs[3].value.trim(), "description": inputs[4].value.trim() };
                        }
                    });
                    return data;
                };

                const getEquipmentData = () => {
                    const equipment = {};
                    const types = ['武器', '头部', '上身', '下身', '饰品A', '饰品B'];
                    types.forEach(type => {
                        const nameInput = document.querySelector(`input[name="装备_${type}_名称"]`);
                        const name = nameInput ? nameInput.value.trim() : "";
                        const descTextarea = document.querySelector(`textarea[name="装备_${type}_描述"]`);
                        const description = descTextarea ? descTextarea.value.trim() : "";

                        equipment[type] = { name, description };

                        if (type === '武器') {
                            equipment[type].AD = getNumber(document.querySelector(`input[name="装备_武器_AD"]`)?.value);
                            equipment[type].AP = getNumber(document.querySelector(`input[name="装备_武器_AP"]`)?.value);
                        } else if (type !== '饰品A' && type !== '饰品B') {
                            equipment[type].PhyDef = getNumber(document.querySelector(`input[name="装备_${type}_PhyDef"]`)?.value);
                            equipment[type].MagDef = getNumber(document.querySelector(`input[name="装备_${type}_MagDef"]`)?.value);
                        }
                    });
                    return equipment;
                };

                // Build the character data object according to the new structure
                const characterData = {
                    "姓名": getValue('name') || '{{user}}',
                    "性别": getValue('gender'),
                    "年龄": getNumberValue('age'),
                    "外貌": getValue('appearance'),
                    "种族": getValue('race') === '自定义' ? getValue('race-custom') : getValue('race'),
                    "总等级": getNumberValue('total-level'),
                    "职业表": getTableData('class-tbody'),
                    "种族表": getTableData('race-tbody'),
                    "能力表": {
                        "HP": { "当前值": null, "最大值": null },
                        "MP": { "当前值": null, "最大值": null },
                        "物理攻击": null,
                        "魔法攻击": null,
                        "物理防御": null,
                        "魔法防御": null,
                        "综合抗性": getAbilityValue('综合抗性:'),
                        "特殊性": getAbilityValue('特殊性:'),
                        "力量": getAbilityValue('力量:'),
                        "智力": getAbilityValue('智力:'),
                        "敏捷": getAbilityValue('敏捷:'),
                        "魅力": getAbilityValue('魅力:'),
                        "幸运": getAbilityValue('幸运:'),
                    },
                    "阵营属性": {
                        "善恶值": getNumberValue('alignment-value'),
                        "阵营描述": ""
                    },
                    "背包": getTableData('inventory-tbody'),
                    "装备栏": getEquipmentData(),
                    "法术技能": getTableData('spell-tbody'),
                };


                // Prepare and send the final message
                const finalMessage = getValue('background-story');
                if (!finalMessage) {
                    if (typeof toastr !== 'undefined') toastr.warning('背景故事为空，无法生成开局。');
                    return;
                }
                eventEmit('era:updateByObject', { '角色面板': characterData });
                await createChatMessages([{ role: 'user', message: `请根据我的背景生成开局：\n${finalMessage}` }]);
                console.log('sleep中');
                await sleep(700); 
                const variables = await getVariables({ type: 'chat' });
                console.log('variables:', _.get(variables,"stat_data.角色面板"));
                console.log('sleep结束，触发slash');
                await triggerSlash(`/trigger`);
                if (typeof toastr !== 'undefined') toastr.success('角色开局已生成并发送！！!');
            }catch (error) {
                console.error('角色生成或更新失败:', error);
                if (typeof toastr !== 'undefined') toastr.error('操作失败，请检查控制台获取详情。');
                else console.error('操作失败，请检查控制台。');
            }
        });
    });
    function sleep(milliseconds) {
        return new Promise(resolve => setTimeout(resolve, milliseconds));
    }
    function updateTotalLevel() {
        let total = 0;
        const classLevels = document.querySelectorAll('input[name="职业_等级"]');
        const raceLevels = document.querySelectorAll('input[name="种族_等级"]');
        classLevels.forEach(input => { total += parseInt(input.value, 10) || 0; });
        raceLevels.forEach(input => { total += parseInt(input.value, 10) || 0; });
        document.getElementById('total-level').value = total;
    }

    function addRow(tbodyId, templateId) {
        const tbody = document.getElementById(tbodyId);
        const template = document.getElementById(templateId);
        const clone = template.content.cloneNode(true);
        tbody.appendChild(clone);
        updateTotalLevel();
    }

    function deleteRow(button) {
        button.closest('tr').remove();
        updateTotalLevel();
    }
    function handleMinMaxInput(input) {
        const max = input.hasAttribute('max') ? parseInt(input.getAttribute('max'), 10) : null;
        const min = input.hasAttribute('min') ? parseInt(input.getAttribute('min'), 10) : null;

        if (input.value === '') {
            return;
        }

        let value = parseInt(input.value, 10);

        if (isNaN(value)) {
            input.value = min !== null ? min : 0;
            return;
        }

        if (max !== null && value > max) {
            input.value = max;
        } else if (min !== null && value < min) {
            input.value = min;
        }
    }
</script>

