                        rowData = { "name": name, "level": inputs[1].value.trim(), "消耗MP": inputs[2].value.trim(), "伤害": inputs[3].value.trim(), "description": inputs[4].value.trim() };
                    }
                    data.push(rowData);
                });
                return data;
            };

            const getEquipmentData = () => {
                const equipment = {};
                const types = ['武器', '头部', '上身', '下身', '饰品A', '饰品B'];
                types.forEach(type => {
                    const nameInput = document.querySelector(`input[name="装备_${type}_名称"]`);
                    const name = nameInput ? nameInput.value.trim() : "";
                    const descTextarea = document.querySelector(`textarea[name="装备_${type}_描述"]`);
                    const description = descTextarea ? descTextarea.value.trim() : "";

                    equipment[type] = { name, description };

                    if (type === '武器') {
                        equipment[type].AD = getNumber(document.querySelector(`input[name="装备_武器_AD"]`)?.value);
                        equipment[type].AP = getNumber(document.querySelector(`input[name="装备_武器_AP"]`)?.value);
                    } else if (type !== '饰品A' && type !== '饰品B') {
                        equipment[type].PhyDef = getNumber(document.querySelector(`input[name="装备_${type}_PhyDef"]`)?.value);
                        equipment[type].MagDef = getNumber(document.querySelector(`input[name="装备_${type}_MagDef"]`)?.value);
                    }
                });
                return equipment;
            };

            // Build and return the character data object
            return {
                "姓名": getValue('name'),
                "性别": getValue('gender'),
                "年龄": getNumberValue('age'),
                "外貌": getValue('appearance'),
                "种族": getValue('race') === '自定义' ? getValue('race-custom') : getValue('race'),
                "总等级": getNumberValue('total-level'),
                "职业表": getTableData('class-tbody'),
                "种族表": getTableData('race-tbody'),
                "能力表": {
                    "HP": { "当前值": null, "最大值": null },
                    "MP": { "当前值": null, "最大值": null },
                    "物理攻击": null,
                    "魔法攻击": null,
                    "物理防御": null,
                    "魔法防御": null,
                    "综合抗性": getAbilityValue('综合抗性:'), "特殊性": getAbilityValue('特殊性:'),
                    "力量": getAbilityValue('力量:'), "智力": getAbilityValue('智力:'),
                    "敏捷": getAbilityValue('敏捷:'), "魅力": getAbilityValue('魅力:'),
                    "幸运": getAbilityValue('幸运:')
                },
                "阵营属性": { "善恶值": getNumberValue('alignment-value') },
                "背包": getTableData('inventory-tbody'),
                "法术技能": getTableData('spell-tbody'),
                "背景故事": getValue('background-story'),
                "装备栏": getEquipmentData()
            };
        }


        function saveCustomPreset() {
            const name = document.getElementById('custom-preset-name').value.trim();
            if (!name) {
                alert('请输入一个有效的存档名称。');
                return;
            }

            const characterData = getCharacterDataFromForm();

            let customSaves = JSON.parse(localStorage.getItem('customCharacterPresets')) || {};
            customSaves[name] = characterData;

            localStorage.setItem('customCharacterPresets', JSON.stringify(customSaves));

            alert(`角色 "${name}" 已保存！`);
            loadCustomPresets(); // Refresh the dropdown
        }

        function deleteCustomPreset() {
            const presetSelect = document.getElementById('character-preset');
            const selectedValue = presetSelect.value;

            if (!selectedValue.startsWith('custom_')) {
                alert('请从下拉菜单中选择一个“自定义存档”进行删除。');
                return;
            }

            if (!confirm(`您确定要删除预设 "${selectedValue.replace('custom_', '')}" 吗？此操作不可撤销。`)) {
                return;
            }

            const presetName = selectedValue.replace('custom_', '');
            let customSaves = JSON.parse(localStorage.getItem('customCharacterPresets')) || {};

            delete customSaves[presetName];

            localStorage.setItem('customCharacterPresets', JSON.stringify(customSaves));

            alert(`预设 "${presetName}" 已被删除。`);

            clearForm();
            loadCustomPresets();
        }

        function loadCustomPresets() {
            const presetSelect = document.getElementById('character-preset');

            // Remove existing custom presets to avoid duplication
            const existingOptgroup = presetSelect.querySelector('optgroup[label="自定义存档"]');
            if (existingOptgroup) {
                existingOptgroup.remove();
            }

            const customSaves = JSON.parse(localStorage.getItem('customCharacterPresets')) || {};
            if (Object.keys(customSaves).length === 0) return;

            const optgroup = document.createElement('optgroup');
            optgroup.label = '自定义存档';

            for (const name in customSaves) {
                const option = document.createElement('option');
                option.value = `custom_${name}`;
                option.textContent = name;
                optgroup.appendChild(option);
            }
            presetSelect.appendChild(optgroup);
        }

        document.getElementById('save-preset-btn').addEventListener('click', saveCustomPreset);
        document.getElementById('delete-preset-btn').addEventListener('click', deleteCustomPreset);

        // --- Import/Export ---
        function exportPreset() {
            const presetSelect = document.getElementById('character-preset');
            const selectedValue = presetSelect.value;

            if (!selectedValue.startsWith('custom_')) {
                alert('请先从下拉菜单中选择一个“自定义存档”进行导出。');
                return;
            }

            const presetName = selectedValue.replace('custom_', '');
            const customSaves = JSON.parse(localStorage.getItem('customCharacterPresets')) || {};
            const characterData = customSaves[presetName];

            if (!characterData) {
                alert(`错误：找不到名为 "${presetName}" 的已存预设。`);
                return;
            }

            const jsonString = JSON.stringify(characterData, null, 2);
            const blob = new Blob([jsonString], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${presetName}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }

        function importPreset() {
            const input = document.createElement('input');
            input.type = 'file';
            input.accept = '.json,application/json';
            input.onchange = e => {
                const file = e.target.files[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = event => {
                    try {
                        const characterData = JSON.parse(event.target.result);
                        const presetName = file.name.replace(/\.json$/, '').trim();

                        if (!presetName) {
                            alert('无法从文件名中获取有效的预设名称。');
                            return;
                        }

                        // Save to localStorage
                        let customSaves = JSON.parse(localStorage.getItem('customCharacterPresets')) || {};
                        customSaves[presetName] = characterData;
                        localStorage.setItem('customCharacterPresets', JSON.stringify(customSaves));

                        // Refresh dropdown
                        loadCustomPresets();

                        // Apply the preset to the form
                        applyPreset(characterData);

                        // Set the dropdown to the newly imported preset and update the name input
                        document.getElementById('character-preset').value = `custom_${presetName}`;
                        document.getElementById('custom-preset-name').value = presetName;

                        alert(`预设 "${presetName}" 已成功导入并保存！`);
                    } catch (error) {
                        console.error("导入预设失败:", error);
                        alert('导入失败，请确保文件是正确的JSON格式。');
                    }
                };
                reader.readAsText(file);
            };
            input.click();
        }

        document.getElementById('export-preset-btn').addEventListener('click', exportPreset);
        document.getElementById('import-preset-btn').addEventListener('click', importPreset);

        function clearForm() {
            // Reset basic inputs
            document.getElementById('name').value = '';
            document.getElementById('gender').value = '';
            document.getElementById('age').value = '';
            document.getElementById('appearance').value = '';
            document.getElementById('race').value = '';
            document.getElementById('race-custom').value = '';
            document.getElementById('race-custom-group').classList.add('hidden');

            // Reset ability scores
            const abilityFieldset = Array.from(document.querySelectorAll('legend')).find(lg => lg.textContent === '能力表').parentElement;
            if (abilityFieldset) {
                abilityFieldset.querySelectorAll('input[type="number"]').forEach(input => input.value = '');
            }

            // Reset alignment
            document.getElementById('alignment-value').value = '0';

            // Clear and reset tables
            ['class-tbody', 'race-tbody', 'inventory-tbody', 'spell-tbody'].forEach(tbodyId => {
                const tbody = document.getElementById(tbodyId);
                tbody.innerHTML = '';
                let templateId = '';
                if (tbodyId.includes('class')) templateId = 'class-template';
                if (tbodyId.includes('race')) templateId = 'race-template';
                if (tbodyId.includes('inventory')) templateId = 'inventory-template';
                if (tbodyId.includes('spell')) templateId = 'spell-template';
                addRow(tbodyId, templateId);
            });

            // Reset equipment
            document.querySelectorAll('.equipment-container input, .equipment-container textarea').forEach(el => el.value = '');

            // Reset background story
            document.getElementById('background-story').value = '';

            updateTotalLevel();
        }

        function applyPreset(preset) {
            if (!preset) return;

            clearForm();

            // Fill basic info
            if (preset.种族) {
                document.getElementById('race').value = preset.种族;
            }

            // Fill abilities
            const abilityFieldset = Array.from(document.querySelectorAll('legend')).find(lg => lg.textContent === '能力表').parentElement;
            if (abilityFieldset && preset.能力表) {
                for (const [key, value] of Object.entries(preset.能力表)) {
                    const label = Array.from(abilityFieldset.querySelectorAll('label')).find(l => l.textContent.includes(key));
                    if (label && label.nextElementSibling) {
                        label.nextElementSibling.value = value;
                    }
                }
            }

            // Fill alignment
            if (preset.阵营属性) {
                document.getElementById('alignment-value').value = preset.阵营属性.善恶值 || 0;
            }

            // Fill tables
            populateTable('class-tbody', 'class-template', preset.职业表, ['职业', '等级', 'description']);
            populateTable('race-tbody', 'race-template', preset.种族表, ['种族', '等级', 'description']);
            populateTable('inventory-tbody', 'inventory-template', preset.背包, ['物品名称', '数量', '描述']);
            populateTable('spell-tbody', 'spell-template', preset.法术技能, ['name', 'level', '消耗MP', '伤害', 'description']);

            // Fill equipment
            if (preset.装备栏) {
                for (const [type, data] of Object.entries(preset.装备栏)) {
                    const nameInput = document.querySelector(`input[name="装备_${type}_名称"]`);
                    if (nameInput) nameInput.value = data.name || '';

                    const descTextarea = document.querySelector(`textarea[name="装备_${type}_描述"]`);
                    if(descTextarea) descTextarea.value = data.description || '';

                    if (type === '武器') {
                        const adInput = document.querySelector(`input[name="装备_武器_AD"]`);
                        if(adInput) adInput.value = data.AD || '';
                        const apInput = document.querySelector(`input[name="装备_武器_AP"]`);
                        if(apInput) apInput.value = data.AP || '';
                    } else if (type !== '饰品A' && type !== '饰品B') {
                        const phyDefInput = document.querySelector(`input[name="装备_${type}_PhyDef"]`);
                        if(phyDefInput) phyDefInput.value = data.PhyDef || '';
                        const magDefInput = document.querySelector(`input[name="装备_${type}_MagDef"]`);
                        if(magDefInput) magDefInput.value = data.MagDef || '';
                    }
                }
            }

            // Fill background story
            if (preset.背景故事) {
                document.getElementById('background-story').value = preset.背景故事;
            }

            updateTotalLevel();
        }

        function populateTable(tbodyId, templateId, data, fields) {
            const tbody = document.getElementById(tbodyId);
            tbody.innerHTML = ''; // Clear existing rows
            if (!data || data.length === 0) {
                addRow(tbodyId, templateId);
                return;
            }

            data.forEach(item => {
                const template = document.getElementById(templateId);
                const clone = template.content.cloneNode(true);
                const tr = clone.querySelector('tr');
                const inputs = clone.querySelectorAll('input, textarea');

                fields.forEach((field, index) => {
                    if (inputs[index] && item.hasOwnProperty(field)) {
                        inputs[index].value = item[field] !== undefined && item[field] !== null ? item[field] : '';
                    }
                });

                if (tbodyId === 'class-tbody') {
                    tr.dataset.currentExp = item['当前经验值'] !== undefined ? item['当前经验值'] : 0;
                    tr.dataset.neededExp = item['升级所需经验值'] !== undefined ? item['升级所需经验值'] : '';
                } else if (tbodyId === 'race-tbody') {
                    tr.dataset.currentProgress = item['当前进度'] !== undefined ? item['当前进度'] : 0;
                    tr.dataset.neededProgress = item['升级所需进度'] !== undefined ? item['升级所需进度'] : '';
                }

                tbody.appendChild(clone);
            });
        }

        // --- Page Transition ---
        const coverScreen = document.getElementById('cover-screen');
        const startBtn = document.getElementById('start-btn');
        const characterSheet = document.getElementById('character-sheet');

        startBtn.addEventListener('click', () => {
            coverScreen.style.opacity = '0';
            setTimeout(() => {
                coverScreen.classList.add('hidden');
                document.body.style.overflow = 'auto';
                document.body.style.background = "#fdf5e6 url('https://www.transparenttextures.com/patterns/old-paper.png')";
                characterSheet.classList.remove('hidden');
            }, 1000);
        });

        loadCustomPresets(); // Load custom presets on page load

        // --- Initial Rows ---
        addRow('class-tbody', 'class-template');
        addRow('race-tbody', 'race-template');
        addRow('inventory-tbody', 'inventory-template');
        addRow('spell-tbody', 'spell-template');
        updateTotalLevel();

        // --- Event Delegation for Level Calculation ---
        const sheet = document.getElementById('character-sheet');
        sheet.addEventListener('input', (event) => {
            if (event.target.name === '职业_等级' || event.target.name === '种族_等级') {
                updateTotalLevel();
            }
        });

        document.getElementById('confirm-btn').addEventListener('click', async () => {
            // --- Validation ---
            if (typeof toastr === 'undefined') {
                console.error('Toastr not loaded!');
                alert('A required library is missing. Please check the console.');
                return;
            }

            // 1. Basic Info
            const basicInfoFields = [
                { id: 'name', name: '姓名' },
                { id: 'gender', name: '性别' },
                { id: 'race', name: '种族' },
                { id: 'age', name: '年龄' },
                { id: 'appearance', name: '外貌' }
            ];

            for (const field of basicInfoFields) {
                const element = document.getElementById(field.id);
                if (!element || element.value.trim() === '') {
                    toastr.warning(`基本信息 "${field.name}" 是必须的。`);
                    return;
                }
            }

            // 1.5. Custom Race Validation
            if (document.getElementById('race').value === '自定义' && document.getElementById('race-custom').value.trim() === '') {
                toastr.warning('请输入自定义种族名称。');
                return;
            }

            // 2. Ability Scores
            const abilityFieldset = Array.from(document.querySelectorAll('legend')).find(lg => lg.textContent === '能力表').parentElement;
            if (abilityFieldset) {
                const abilityInputs = abilityFieldset.querySelectorAll('input[type="number"]');
                for (const input of abilityInputs) {
                    if (input.value.trim() === '') {
                        const label = input.previousElementSibling;
                        toastr.warning(`能力表 "${label.textContent.replace(':', '')}" 是必须的。`);
                        return;
                    }
                }
            }
            // --- End Validation ---
            try {
                if (typeof toastr !== 'undefined') toastr.info('稍等，角色数据更新中...');

                const characterData = getCharacterDataFromForm();

                // Convert array table data back to object for MVU compatibility
                const mvuCompatibleData = JSON.parse(JSON.stringify(characterData));
                const arrayToObject = (arr, key) => arr.reduce((obj, item) => {
                    obj[item[key]] = item;
                    return obj;
                }, {});

                mvuCompatibleData.职业表 = arrayToObject(characterData.职业表, '职业');
                mvuCompatibleData.种族表 = arrayToObject(characterData.种族表, '种族');
                mvuCompatibleData.背包 = arrayToObject(characterData.背包, '物品名称');
                mvuCompatibleData.法术技能 = arrayToObject(characterData.法术技能, 'name');

                // Add currently missing nested objects for full compatibility
                mvuCompatibleData.姓名 = mvuCompatibleData.姓名 || '{{user}}';
                 mvuCompatibleData.阵营属性 = {
                    ...mvuCompatibleData.阵营属性,
                    "阵营描述": ""
                };


                // Prepare and send the final message
                const finalMessage = characterData.背景故事;
                if (!finalMessage) {
                    if (typeof toastr !== 'undefined') toastr.warning('背景故事为空，无法生成开局。');
                    return;
                }

                const mvudata = Mvu.getMvuData({ type: 'chat' });

                _.set(mvudata, 'stat_data.角色面板', mvuCompatibleData);

                await Mvu.replaceMvuData(mvudata, { type: 'message', message_id: 'latest' });

                await setChatMessages([{ message_id: 0, message: "开局初始化完毕" }]);
                await triggerSlash(`/send 请根据我的背景生成开局（剧情为第一卷）：\n${finalMessage}|/trigger`);

                if (typeof toastr !== 'undefined') toastr.success('角色开局已生成并发送！请手动重roll一下！');

            } catch (error) {
                console.error('角色生成或更新失败:', error);
                if (typeof toastr !== 'undefined') toastr.error('操作失败，请检查控制台获取详情。');
                else console.error('操作失败，请检查控制台。');
            }
        });
    });
    function updateTotalLevel() {
        let total = 0;
        const classLevels = document.querySelectorAll('input[name="职业_等级"]');
        const raceLevels = document.querySelectorAll('input[name="种族_等级"]');
        classLevels.forEach(input => { total += parseInt(input.value, 10) || 0; });
        raceLevels.forEach(input => { total += parseInt(input.value, 10) || 0; });
        document.getElementById('total-level').value = total;
    }

    function addRow(tbodyId, templateId) {
        const tbody = document.getElementById(tbodyId);
        const template = document.getElementById(templateId);
        const clone = template.content.cloneNode(true);
        const tr = clone.querySelector('tr');

        if (tbodyId === 'class-tbody') {
            tr.dataset.currentExp = 0;
            tr.dataset.neededExp = null;
        } else if (tbodyId === 'race-tbody') {
            tr.dataset.currentProgress = 0;
            tr.dataset.neededProgress = null;
        }

        tbody.appendChild(clone);
        updateTotalLevel();
    }

    function deleteRow(button) {
        button.closest('tr').remove();
        updateTotalLevel();
    }
    function handleMinMaxInput(input) {
        const max = input.hasAttribute('max') ? parseInt(input.getAttribute('max'), 10) : null;
        const min = input.hasAttribute('min') ? parseInt(input.getAttribute('min'), 10) : null;

        if (input.value === '') {
            return;
        }

        let value = parseInt(input.value, 10);

        if (isNaN(value)) {
            input.value = min !== null ? min : 0;
            return;
        }

        if (max !== null && value > max) {
            input.value = max;
        } else if (min !== null && value < min) {
            input.value = min;
        }
    }
</script>

